function formatarDataMilissegundos(dataMilissegundos) {
  if (!dataMilissegundos) return "";
  const dataObj = new Date(dataMilissegundos);
  if (isNaN(dataObj.getTime())) return "";

  // GMT-3 São Paulo
  dataObj.setHours(dataObj.getHours() - 3);

  const dia = String(dataObj.getDate()).padStart(2, "0");
  const mes = String(dataObj.getMonth() + 1).padStart(2, "0");
  const ano = dataObj.getFullYear();
  const horas = String(dataObj.getHours()).padStart(2, "0");
  const minutos = String(dataObj.getMinutes()).padStart(2, "0");
  const segundos = String(dataObj.getSeconds()).padStart(2, "0");

  return `${ano}-${mes}-${dia} ${horas}:${minutos}:${segundos}`;
}

function formatDateTime(dateString) {
  if (!dateString) return "";
  if (/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$/.test(dateString)) return dateString;
  if (/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/.test(dateString)) return `${dateString}:00`;
  console.warn("Formato de data inesperado:", dateString);
  return dateString;
}

function formatCPF(cpf) {
  const cpfLimpo = String(cpf || "").replace(/\D/g, "");
  if (cpfLimpo.length === 11) {
    return `${cpfLimpo.slice(0, 3)}.${cpfLimpo.slice(3, 6)}.${cpfLimpo.slice(6, 9)}-${cpfLimpo.slice(9, 11)}`;
  }
  return cpf || "";
}

function formatCNPJ(cnpj) {
  const cnpjLimpo = String(cnpj || "").replace(/\D/g, "");
  if (cnpjLimpo.length === 14) {
    return `${cnpjLimpo.slice(0, 2)}.${cnpjLimpo.slice(2, 5)}.${cnpjLimpo.slice(5, 8)}/${cnpjLimpo.slice(8, 12)}-${cnpjLimpo.slice(12, 14)}`;
  }
  return cnpj || "";
}

function isCPFOrCNPJ(cpfCnpj) {
  const cleaned = String(cpfCnpj || "").replace(/\D/g, "");
  if (cleaned.length === 11) return "CPF";
  if (cleaned.length === 14) return "CNPJ";
  return null;
}

function capitalizeName(fullName) {
  if (!fullName) return { fname: "", lname: "", fullname: "" };

