    case "REFUNDED":
      purchaseStatusTranslation = "Compra Reembolsada";
      break;
    case "STARTED":
      purchaseStatusTranslation = "Compra Iniciada";
      break;
    case "UNDER_ANALISYS":
      purchaseStatusTranslation = "Compra em Análise";
      break;
    case "WAITING_PAYMENT":
      purchaseStatusTranslation = "Aguardando Pagamento";
      break;
    default:
      purchaseStatusTranslation = "Status Desconhecido";
  }
}

let translatedChargeType = "";
switch (chargeType) {
  case "SUBSCRIPTION":
    translatedChargeType = "Assinatura";
    break;
  default:
    translatedChargeType = "Cobrança única";
}

// ===============================
// Formatar telefone (mesma regra)
// ===============================
let telefoneFinal = "";
if (telefoneClienteOriginal) {
  const telefoneLimpo = String(telefoneClienteOriginal).replace(/\D/g, "");

  let DDI = "";
  let DDD = "";
  let numero = "";

  if (telefoneLimpo.length > 11) {
    DDI = telefoneLimpo.slice(0, 2);
    DDD = telefoneLimpo.slice(2, 4);
    numero = telefoneLimpo.slice(4);
  } else if (telefoneLimpo.length === 11) {
    DDI = "55";
    DDD = telefoneLimpo.slice(0, 2);
    numero = telefoneLimpo.slice(2);
  } else if (telefoneLimpo.length === 10) {
    DDI = "55";
    DDD = telefoneLimpo.slice(0, 2);
    numero = telefoneLimpo.slice(2);
  } else {
    telefoneFinal = telefoneLimpo;
  }

  if (DDD && numero) {
    if (parseInt(DDD) > 28) {
      if (numero.length === 9 && numero.startsWith("9")) numero = numero.slice(1);
    } else {
      if (numero.length === 8) numero = `9${numero}`;
    }
  }

  if (DDI && DDD && numero) telefoneFinal = `${DDI}${DDD}${numero}`;
}

// ===============================
// Saídas formatadas
// ===============================
const formattedNames = capitalizeName(fullNameAnswer);
const formattedEmail = String(emailAnswer || "").toLowerCase().trim();
const formattedInstagram = String(instagramAnswer || "").toLowerCase().replace(/^@/, "");
const formattedEventDate = formatDateTime(eventDate);

const formattedPaidDate = formatarDataMilissegundos(paidDate) || "";
const formattedSubscriptionExpirationDate = (formatarDataMilissegundos(subscriptionExpirationDate).split(" ")[0]) || "";
const formattedWarrantyDate = (formatarDataMilissegundos(warrantyDate).split(" ")[0]) || "";
const formattedBilletExpirationDate = (formatarDataMilissegundos(billetExpirationDate).split(" ")[0]) || "";

const form_id = offer_code;
const form_name = data?.subscription?.plan?.name || "";

// ===============================
// Resultado final
// ===============================
const result = {
  ...formattedNames,
  email: formattedEmail,
  whatsapp: telefoneFinal,
  instagram: formattedInstagram,
  cpf: cpf,
  cnpj: cnpj,
  transaction_id: transaction_id,
  recurrenceNumber: recurrenceNumber,
  value: value,
  trans_status: purchaseStatusTranslation,
  payment_method: paymentMethodTranslation,
  refund_date: refundDate,
  event_date: formattedEventDate,
  payment_date: formattedPaidDate,
  recurrenceExpirationDate: formattedSubscriptionExpirationDate,
  product_type: translatedChargeType,
  product_id: productId,
  product_name: productName,
  warranty_date: formattedWarrantyDate,
  offer_code: offer_code,
  gateway_comission: gateway_comission,
  billet_barcode: billet_barcode,
  currency: currency,
  bankslip: bankslip,
  billetExpirationDate: formattedBilletExpirationDate,
  form_name: form_name,
  form_id: form_id,
  utm_source: utm_source,
  utm_campaign: utm_campaign,
  utm_term: utm_term,
  utm_medium: utm_medium,
  utm_content: utm_content,
  src: src,
  sck: sck,
  installments: installments,
  refusalReason: refusalReason,
  subscriberCode: subscriberCode,
  planName: planName,
  planId: planId,
  eventId: eventId
};

return [{ json: result }];
